const grades = ["초등","중등","고등"];
const subjects = ["국어","영어","수학","사회","과학"];

function buildEduData() {
  const data = {};
  for (const [rs, ri] of Object.entries(locations)) {
    data[rs] = {};
    for (const [cs, ci] of Object.entries(ri.cities)) {
      const kn = ci.name;
      const classList = [];
      for (const g of grades) for (const s of subjects) {
        const raw = descriptions[g][s];
        classList.push({ grade:g, subject:s, title:kn+" "+g+" "+s+"과외", desc:raw.replace(/{region}/g,kn) });
      }
      data[rs][cs] = { region_display:ri.region_name+" "+kn, name:kn, schools:ci.schools||[], dongs:ci.dongs||[], classes:classList };
    }
  }
  return data;
}
const eduData = buildEduData();

// index.html base64
const INDEX_B64 = "";
function getIndex() {
  const bytes = Uint8Array.from(atob(INDEX_B64), c => c.charCodeAt(0));
  return new TextDecoder("utf-8").decode(bytes);
}

