function handleSearch(q) {
  if (!q) return {redirect:"/directory"};
  const kws = q.split(/\s+/).filter(Boolean);
  const qns = q.replace(/\s+/g,"");
  for (const [rs,ri] of Object.entries(locations)) {
    const rn = ri.region_name, sr = rn.slice(0,2);
    for (const [cs,ci] of Object.entries(ri.cities)) {
      const cn = ci.name, sc = cn.length>2?cn.slice(0,-1):cn;
      const target = rn+" "+cn+" "+(ci.dongs||[]).join(" ");
      if (kws.every(k=>target.includes(k))) return {redirect:"/"+rs+"/"+cs};
      for (const d of (ci.dongs||[])) {
        if (qns.includes(d.replace(/\s/g,""))&&(qns.includes(sr)||qns.includes(sc)||qns.includes(cn)))
          return {redirect:"/"+rs+"/"+cs};
      }
    }
  }
  for (const [rs,ri] of Object.entries(locations)) {
    if (kws.every(k=>ri.region_name.includes(k))) return {redirect:"/directory#"+encodeURIComponent(ri.region_name)};
  }
  return {notFound:q};
}

function handleSuggest(q) {
  if (!q) return [];
  const qns = q.replace(/\s+/g,"");
  const res=[], seen=new Set();
  for (const [rs,ri] of Object.entries(locations)) {
    const rn=ri.region_name, sr=rn.slice(0,2);
    for (const [cs,ci] of Object.entries(ri.cities)) {
      const cn=ci.name, sc=cn.length>2?cn.slice(0,-1):cn;
      const md=(ci.dongs||[]).filter(d=>d.replace(/\s/g,"").includes(qns));
      if (md.length>0) {
        const k=sr+" "+cn+" "+md[0];
        if(!seen.has(k)){seen.add(k);res.push({display:k,url:"/"+rs+"/"+cs});}
      } else if(cn.includes(qns)||sc.includes(qns)) {
        const k=rn+" "+cn;
        if(!seen.has(k)){seen.add(k);res.push({display:k,url:"/"+rs+"/"+cs});}
      }
      if(res.length>=7)break;
    }
    if(res.length>=7)break;
  }
  return res.slice(0,7);
}

addEventListener("fetch", event => {
  event.respondWith(handle(event.request));
});

async function handle(req) {
  const url = new URL(req.url);
  const p = url.pathname;
  const parts = p.split("/").filter(Boolean);
  const H = {"Content-Type":"text/html;charset=UTF-8"};
  const J = {"Content-Type":"application/json;charset=UTF-8"};

    // ── 상담 신청 이메일 전송 ──────────────────────────────
  if (p === "/api/contact" && req.method === "POST") {
    try {
      const data = await req.json();
      const { method, grade, subject, name, contact, school, address, message } = data;

      const html = `
        <div style="font-family:'Apple SD Gothic Neo',sans-serif;max-width:600px;margin:0 auto;background:#f8f9fc;border-radius:12px;overflow:hidden;">
          <div style="background:linear-gradient(135deg,#1A2340,#2a3d6b);padding:28px 32px;">
            <h1 style="color:#C8A96E;margin:0;font-size:22px;">📚 새 상담 신청이 도착했습니다</h1>
            <p style="color:rgba(255,255,255,0.6);margin:6px 0 0;font-size:13px;">은빛과외 홈페이지 상담 신청</p>
          </div>
          <div style="padding:28px 32px;background:#fff;">
            <table style="width:100%;border-collapse:collapse;">
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;width:110px;">학생 이름</td><td style="padding:10px 0;border-bottom:1px solid #eee;font-weight:600;color:#1A2340;">${name || '-'}</td></tr>
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;">연락처</td><td style="padding:10px 0;border-bottom:1px solid #eee;font-weight:600;color:#1A2340;">${contact || '-'}</td></tr>
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;">학생 학교</td><td style="padding:10px 0;border-bottom:1px solid #eee;font-weight:600;color:#1A2340;">${school || "-"}</td></tr>
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;">거주 지역</td><td style="padding:10px 0;border-bottom:1px solid #eee;font-weight:600;color:#1A2340;">${address || '-'}</td></tr>
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;">수업 방식</td><td style="padding:10px 0;border-bottom:1px solid #eee;color:#1A2340;">${method || '-'}</td></tr>
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;">학년</td><td style="padding:10px 0;border-bottom:1px solid #eee;color:#1A2340;">${grade || '-'}</td></tr>
              <tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#888;font-size:13px;">희망 과목</td><td style="padding:10px 0;border-bottom:1px solid #eee;color:#1A2340;">${subject || '-'}</td></tr>
              <tr><td style="padding:10px 0;color:#888;font-size:13px;vertical-align:top;">문의 사항</td><td style="padding:10px 0;color:#1A2340;line-height:1.6;">${message || '없음'}</td></tr>
            </table>
          </div>
          <div style="padding:16px 32px;background:#f8f9fc;font-size:12px;color:#aaa;text-align:center;">
            은빛과외 · eunshinestudy.com · 010-2337-0458
          </div>
        </div>`;

      const res = await fetch("https://api.resend.com/emails", {
        method: "POST",
        headers: {
          "Authorization": "Bearer " + (typeof RESEND_API_KEY !== "undefined" ? RESEND_API_KEY : ""),
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          from: "은빛과외 상담신청 <noreply@eunshinestudy.com>",
          to: ["thdmsdidfl@naver.com"],
          subject: "📚 [은빛과외] 새 상담 신청 - " + (name || "이름 없음") + " (" + (grade || "") + ")",
          html: html
        })
      });

      if (res.ok) {
        return new Response(JSON.stringify({ok:true}), {headers:J, status:200});
      } else {
        const err = await res.text();
        return new Response(JSON.stringify({ok:false, error:err}), {headers:J, status:500});
      }
    } catch(e) {
      return new Response(JSON.stringify({ok:false, error:e.message}), {headers:J, status:500});
    }
  }

  
  // ── 배너 이미지 서빙 ──
  if (p === "/img/banner1.png") {
    const bytes = Uint8Array.from(atob(BANNER1_B64), c => c.charCodeAt(0));
    return new Response(bytes, {headers:{"Content-Type":"image/png","Cache-Control":"public, max-age=86400"}});
  }
  if (p === "/img/banner2.png") {
    const bytes = Uint8Array.from(atob(BANNER2_B64), c => c.charCodeAt(0));
    return new Response(bytes, {headers:{"Content-Type":"image/png","Cache-Control":"public, max-age=86400"}});
  }

  if (p==="/"||p==="") return new Response(getIndex(),{headers:H});
  if (p === "/sitemap.xml") {
    const urls = ["https://eunshinestudy.com/", "https://eunshinestudy.com/directory"];
    for (const [rs, ri] of Object.entries(locations)) {
      for (const cs of Object.keys(ri.cities)) {
        urls.push("https://eunshinestudy.com/" + rs + "/" + cs);
      }
    }
    const xml = `<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
${urls.map(u => `  <url><loc>${u}</loc><changefreq>weekly</changefreq><priority>0.8</priority></url>`).join("\n")}
</urlset>`;
    return new Response(xml, { headers: { "Content-Type": "application/xml;charset=UTF-8" } });
  }
  if (p==="/directory") return new Response(buildDirectoryPage(),{headers:H});
  if (p==="/search") {
    const q=(url.searchParams.get("q")||"").trim();
    const r=handleSearch(q);
    if(r.redirect) return Response.redirect(new URL(r.redirect,url.origin).href,302);
    return new Response(`<script>alert('\uAC80\uC0C9 \uACB0\uACFC\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.');location.href='/directory';</script>`,{headers:H});
  }
  if (p==="/api/suggest") {
    const q=(url.searchParams.get("q")||"").trim();
    return new Response(JSON.stringify(handleSuggest(q)),{headers:J});
  }
  if (parts.length===2) {
    const html=buildCityPage(parts[0],parts[1]);
    if(!html) return Response.redirect(new URL("/directory",url.origin).href,302);
    return new Response(html,{headers:H});
  }
  if (parts.length===3) {
    const dong = decodeURIComponent(parts[2]);
    const html = buildDongPage(parts[0], parts[1], dong);
    if(!html) return Response.redirect(new URL("/directory",url.origin).href,302);
    return new Response(html,{headers:H});
  }
  if (parts.length===5) {
    const dong = decodeURIComponent(parts[2]);
    const html = buildDongDetailPage(parts[0],parts[1],dong,decodeURIComponent(parts[3]),decodeURIComponent(parts[4]));
    if(!html) return Response.redirect(new URL("/directory",url.origin).href,302);
    return new Response(html,{headers:H});
  }
  if (parts.length===4) {
    const html=buildDetailPage(parts[0],parts[1],decodeURIComponent(parts[2]),decodeURIComponent(parts[3]));
    if(!html) return Response.redirect(new URL("/directory",url.origin).href,302);
    return new Response(html,{headers:H});
  }
  return new Response("Not Found",{status:404});
}
